@RestController
@RequestMapping("/api/webhook")
class WebhookController {

    private final RestTemplate restTemplate;
    private final UrlValidator urlValidator;

    public WebhookController(RestTemplate restTemplate, UrlValidator urlValidator) {
        this.restTemplate = restTemplate;
        this.urlValidator = urlValidator;
    }

    @PostMapping("/fetch")
    public ResponseEntity<?> handleWebhook(@RequestBody WebhookRequest request) {
        try {
            if (!urlValidator.isValidUrl(request.getUrl())) {
                return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                        .body(Map.of("error", "Invalid or unsafe URL provided"));
            }

            String content = restTemplate.getForObject(request.getUrl(), String.class);
            
            WebhookResponse response = new WebhookResponse();
            response.setStatus("success");
            response.setContent(content);
            response.setUrl(request.getUrl());
            response.setTimestamp(System.currentTimeMillis());
            
            return ResponseEntity.ok(response);
            
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("error", "Failed to fetch content: " + e.getMessage()));
        }
    }
}

