@org.springframework.stereotype.Component
class UrlValidator {

    private static final Set<String> ALLOWED_SCHEMES = Set.of("http", "https");
    private static final Set<String> BLOCKED_HOSTS = Set.of(
            "localhost",
            "127.0.0.1",
            "0.0.0.0",
            "::1"
    );
    
    private static final List<String> PRIVATE_IP_PATTERNS = Arrays.asList(
            "^10\\..*",
            "^172\\.(1[6-9]|2[0-9]|3[0-1])\\..*",
            "^192\\.168\\..*",
            "^169\\.254\\..*",
            "^fc00:.*",
            "^fe80:.*"
    );

    public boolean isValidUrl(String urlString) {
        if (urlString == null || urlString.trim().isEmpty()) {
            return false;
        }

        try {
            URI uri = new URI(urlString);
            
            String scheme = uri.getScheme();
            if (scheme == null || !ALLOWED_SCHEMES.contains(scheme.toLowerCase())) {
                return false;
            }

            String host = uri.getHost();
            if (host == null || host.trim().isEmpty()) {
                return false;
            }

            host = host.toLowerCase();
            if (BLOCKED_HOSTS.contains(host)) {
                return false;
            }

            if (isPrivateOrLocalAddress(host)) {
                return false;
            }

            InetAddress inetAddress = InetAddress.getByName(host);
            
            if (inetAddress.isLoopbackAddress() || 
                inetAddress.isLinkLocalAddress() || 
                inetAddress.isSiteLocalAddress() ||
                inetAddress.isAnyLocalAddress()) {
                return false;
            }

            String ipAddress = inetAddress.getHostAddress();
            for (String pattern : PRIVATE_IP_PATTERNS) {
                if (Pattern.matches(pattern, ipAddress)) {
                    return false;
                }
            }

            return true;

        } catch (UnknownHostException e) {
            return false;
        } catch (Exception e) {
            return false;
        }
    }

    private boolean isPrivateOrLocalAddress(String host) {
        for (String pattern : PRIVATE_IP_PATTERNS) {
            if (Pattern.matches(pattern, host)) {
                return true;
            }
        }
        
        if (host.endsWith(".local") || host.endsWith(".localhost")) {
            return true;
        }

        return false;
    }
}